// NN_03_AI_Agent v1.0.0 - Extract & Validate
// SEC04: Validate chat_id as numeric
// SEC05: Sanitize text input

const item = $input.first()?.json || {};
const body = item.body || {};
const data = item.chat_id ? item : (body.chat_id ? body : item);

const rawChatId = data.chat_id;
const rawText = data.text || data.ai_response || "";

// SEC04: Validate chat_id as numeric
const cidStr = String(rawChatId || ''); 
const cidNum = Number(cidStr); 
const isValidChatId = Number.isInteger(cidNum) && cidNum > 0 && String(cidNum) === cidStr.trim();

// SEC05: Sanitize text
const sanitizedText = String(rawText)
  .replace(/\\/g, '\\\\')
  .replace(/'/g, "''")
  .substring(0, 500);

// SEC04: Safe regex - alphanumeric, spaces, hyphens, punctuation
const allowed = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789 \n\táéíóúÁÉÍÓÚñÑ-.,!?()¿¡';
let isSafeText = true;
for (let i = 0; i < sanitizedText.length; i++) {
  if (!allowed.includes(sanitizedText[i])) {
    isSafeText = false;
    break;
  }
}
const isValidText = isSafeText && sanitizedText.trim().length > 2;

const isValid = isValidChatId && isValidText;

return [{ json: {
  isValid,
  chat_id: isValidChatId ? Number(rawChatId) : null,
  sessionId: String(rawChatId || ''),
  text: sanitizedText,
  _meta: {
    source: "NN_03_AI_Agent",
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id,
    version: "1.0.0"
  }
}}];

// Gate: only pass valid items to AI Agent
const input = $input.first().json;
if (!input.isValid) return [];
return [{ json: input }];

// Gate: pass validation errors to Format Error
const input = $input.first().json;
if (input.isValid) return [];
return [{ json: {
  success: false,
  error_code: "VALIDATION_ERROR",
  error_message: "Invalid chat_id or text for AI Agent",
  data: null,
  _meta: {
    source: "NN_03_AI_Agent",
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id,
    version: "1.0.0"
  }
}}];

// NN_03_AI_Agent v1.0.0 - Format AI Response
let chatId = null;
if ($('Extract & Validate').isExecuted) {
  chatId = $('Extract & Validate').first()?.json?.chat_id;
}

const aiOutput = $input.first()?.json || {};

// If AI Agent crashed and passed an error message
if (aiOutput.error) {
  return [{ json: {
    success: false,
    error_code: "AI_AGENT_RATE_LIMIT",
    error_message: aiOutput.error.message || aiOutput.error || "Error de la API de AI",
    data: { chat_id: chatId },
    _meta: { source: "NN_03_AI_Agent", timestamp: new Date().toISOString(), workflow_id: $workflow.id, version: "1.0.0" }
  }}];
}

const aiResp = aiOutput?.output;
if (!aiResp || String(aiResp).trim().length === 0) {
  return [{ json: {
    success: false,
    error_code: "AI_AGENT_ERROR",
    error_message: aiOutput?.error?.message || aiOutput?.message || "AI Agent no generó respuesta",
    data: { chat_id: chatId },
    _meta: { source: "NN_03_AI_Agent", timestamp: new Date().toISOString(), workflow_id: $workflow.id, version: "1.0.0" }
  }}];
}

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      intent: "AI_RESPONSE",
      chat_id: chatId,
      ai_response: aiResp
    },
    _meta: {
      source: "NN_03_AI_Agent",
      timestamp: new Date().toISOString(),
      workflow_id: $workflow.id,
      version: "1.0.0"
    }
  }
}];
